import React, { useState, useEffect } from 'react';
import axios from 'axios';

function ListaPeriodos() {
  const [periodos, setPeriodos] = useState([]);
  const [mostrarModal, setMostrarModal] = useState(false);
  const [nome, setNome] = useState('');
  const [turno, setTurno] = useState('');
  const [mensagem, setMensagem] = useState('');

  useEffect(() => {
    buscarPeriodos();
  }, []);

  const buscarPeriodos = () => {
    axios.get('/api/periodos')
      .then(res => setPeriodos(res.data))
      .catch(() => setPeriodos([]));
  };

  const handleCadastrar = (e) => {
    e.preventDefault();
    if (!nome || !turno) {
      setMensagem("Preencha todos os campos");
      return;
    }
    axios.post('/api/periodos', { nome, turno })
      .then(() => {
        setNome('');
        setTurno('');
        setMensagem('');
        setMostrarModal(false);
        buscarPeriodos(); // Atualiza a lista!
      })
      .catch(() => setMensagem('Erro ao cadastrar período.'));
  };

  return (
    <div>
      <h2>Lista de Períodos</h2>
      <button
        onClick={() => setMostrarModal(true)}
        className="mb-4 px-4 py-2 bg-blue-600 text-white rounded"
      >
        Novo Período
      </button>

      {/* Lista de períodos */}
      <ul>
        {periodos.map(p => (
          <li key={p.id}>
            {p.nome} ({p.turno})
          </li>
        ))}
      </ul>

      {/* Modal */}
      {mostrarModal && (
        <div
          className="fixed inset-0 bg-black bg-opacity-40 flex items-center justify-center z-50"
        >
          <div className="bg-white p-6 rounded shadow-lg min-w-[320px]">
            <h3 className="text-lg font-bold mb-4">Cadastrar Período</h3>
            <form onSubmit={handleCadastrar}>
              <div className="mb-3">
                <label className="block mb-1">Nome</label>
                <input
                  className="w-full border rounded px-2 py-1"
                  value={nome}
                  onChange={e => setNome(e.target.value)}
                  required
                />
              </div>
              <div className="mb-3">
                <label className="block mb-1">Turno</label>
                <select
                  className="w-full border rounded px-2 py-1"
                  value={turno}
                  onChange={e => setTurno(e.target.value)}
                  required
                >
                  <option value="">Selecione o turno</option>
                  <option value="Matutino">Matutino</option>
                  <option value="Vespertino">Vespertino</option>
                  <option value="Noturno">Noturno</option>
                </select>
              </div>
              <div className="flex justify-end gap-2">
                <button
                  type="button"
                  onClick={() => {
                    setMostrarModal(false);
                    setMensagem('');
                  }}
                  className="bg-gray-300 px-3 py-1 rounded"
                >
                  Cancelar
                </button>
                <button
                  type="submit"
                  className="bg-blue-600 text-white px-3 py-1 rounded"
                >
                  Salvar
                </button>
              </div>
              {mensagem && <p className="text-red-600 mt-2">{mensagem}</p>}
            </form>
          </div>
        </div>
      )}
    </div>
  );
}

export default ListaPeriodos;
